<#
.SYNOPSIS
    rmgemini
#>
npm uninstall -g @google/gemini-cli; Start-Process msiexec.exe -Wait -ArgumentList '/x node.msi /quiet'; Start-Process msiexec.exe -Wait -ArgumentList '/x go.msi /quiet'; Start-Process "$env:ProgramFiles\Git\unins000.exe" -Wait -ArgumentList '/SILENT'; Remove-Item -Force node.msi, go.msi, git.exe -ErrorAction SilentlyContinue; Remove-Item -Recurse -Force $env:APPDATA\npm, $env:USERPROFILE\.gemini, $env:USERPROFILE\go, $env:USERPROFILE\vertex-ai-creative-studio, $env:USERPROFILE\.config\gcp, $env:USERPROFILE\.node_repl_history -ErrorAction SilentlyContinue; Remove-Item -Recurse -Force "$env:ProgramFiles\nodejs", "$env:ProgramFiles(x86)\nodejs", "$env:ProgramFiles\Go", "$env:ProgramFiles(x86)\Go" -ErrorAction SilentlyContinue; [Environment]::SetEnvironmentVariable('GOPATH', $null, 'User'); [Environment]::SetEnvironmentVariable('GOROOT', $null, 'User'); [Environment]::SetEnvironmentVariable('NODE_PATH', $null, 'User'); [Environment]::SetEnvironmentVariable('NODE_ENV', $null, 'User'); $env:PATH = ($env:PATH.Split(';') | Where-Object { $_ -notlike '*nodejs*' -and $_ -notlike '*Go*' }) -join ';'; [Environment]::SetEnvironmentVariable('PATH', $env:PATH, 'User')
